CREATE INDEX IF NOT EXISTS idx_error_logs_occurred         ON public.error_logs(occurred_at DESC);
CREATE INDEX IF NOT EXISTS idx_email_send_log_msg          ON public.email_send_log(message_id, created_at DESC);
